mapper.select:
SELECT f.*
FROM flight f
WHERE f.dept_city = #{request.deptCity}
  AND f.arr_city = #{request.arrCity}
  AND f.flight_date = #{request.flightDate}
  AND NOT EXISTS (
    SELECT 1
    FROM flight_segment fs
             JOIN segment_instance si ON fs.segment_instance_id = si.id
    WHERE fs.flight_id = f.id
      AND si.status != 'OPEN'
)
